2156→\begin{proposition}[{\cite[\href{https://stacks.math.columbia.edu/tag/0982}{Tag 0982}, (3) $\implies$ (2)]{stacks-project}}] % actually iff, but we only need this direction
2157→  \label{thm:w-contractible-retraction}
2158→  \uses{def:w-contractible-ring,def:w-strictly-local-ring,def:extremally-disconnected}
2159→  If $A$ is w-contractible, every ind-étale, faithfully flat map $A \to B$ has a retraction.
2160→  \lean{IsWContractibleRing.exists_retraction}
2161→  \leanok
2162→\end{proposition}
