2213→\begin{theorem}[{\cite[Theorem 2.4.9]{proetale}}, {\cite[\href{https://stacks.math.columbia.edu/tag/0983}{Tag 0983}]{stacks-project}}]
2214→  For any ring $A$, there exists an ind-étale faithfully flat $A$-algebra $D$ with $D$ w-contractible.
2215→  \label{thm:ind-etale-w-contractible-cover-exists}
2216→  \uses{def:w-contractible-ring,def:ind-etale}
2217→  \lean{exists_isWContractibleRing}
2218→  \leanok
2219→\end{theorem}
