2228→    For any ring $A$, there exists an ind-étale faithfully flat $A$-algebra $B$ such that
2229→    every ind-étale faithfully flat map $B \to C$ has a retraction.
2230→    \uses{def:ind-etale}
2231→    \label{cor:ind-etale-retraction-cover-exists}
2232→    \lean{exists_forall_exists_retraction}
2233→    \leanok
2234→\end{corollary}
