2236→\begin{proof}
2237→    \leanok
2238→    \uses{thm:ind-etale-w-contractible-cover-exists, thm:w-contractible-retraction}
2239→    This follows from \Cref{thm:ind-etale-w-contractible-cover-exists} and \Cref{thm:w-contractible-retraction}.
2240→\end{proof}
